// hooks/useAI.js — Updated for Gemini backend
import { useState, useCallback } from "react";

const API_BASE = process.env.REACT_APP_API_URL || "http://localhost:3000";

export function useAI() {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // GET static topic content (explanation, formulas, shortcuts, examples)
  const generateTopicContent = useCallback(async (topic) => {
    setLoading(true);
    setError(null);
    try {
      // Convert "Profit and Loss" → "profit-and-loss" to match backend slug
      const slug = topic.trim().toLowerCase().replace(/\s+/g, "-");

      const res = await fetch(`${API_BASE}/topic/${slug}`);  // ← changed

      if (!res.ok) throw new Error(`Server error: ${res.status}`);
      const json = await res.json();
      if (!json.success) throw new Error(json.error || "Unknown error");
      return json.data;
    } catch (err) {
      setError(err.message);
      return null;
    } finally {
      setLoading(false);
    }
  }, []);

  // POST to Gemini — generate 5 MCQs
  const generateQuiz = useCallback(async (topic, difficulty = "medium") => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch(`${API_BASE}/generate-questions`, {  // ← changed
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ topic, difficulty }),  // ← count replaced with difficulty
      });
      if (!res.ok) throw new Error(`Server error: ${res.status}`);
      const json = await res.json();
      return json.questions;
    } catch (err) {
      setError(err.message);
      return null;
    } finally {
      setLoading(false);
    }
  }, []);

  return { generateTopicContent, generateQuiz, loading, error };
}
